import{c as d,Q as a,j as r,m as l}from"./chunks/framework.BIBjCrbN.js";const b=JSON.parse('{"title":"奖学金信息","description":"中国博士奖学金类型汇总，包括CSC奖学金、学校奖学金和导师助研津贴","frontmatter":{"title":"奖学金信息","description":"中国博士奖学金类型汇总，包括CSC奖学金、学校奖学金和导师助研津贴"},"headers":[],"relativePath":"guide/csc-scholarship.md","filePath":"guide/csc-scholarship.md","lastUpdated":1780110618000}'),e={name:"guide/csc-scholarship.md"};function o(i,t,h,n,s,c){return a(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="奖学金与资助信息" tabindex="-1">奖学金与资助信息 <a class="header-anchor" href="#奖学金与资助信息" aria-label="Permalink to &quot;奖学金与资助信息&quot;">​</a></h1><h2 id="主要奖学金类型" tabindex="-1">主要奖学金类型 <a class="header-anchor" href="#主要奖学金类型" aria-label="Permalink to &quot;主要奖学金类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>奖学金类型</th><th>资助方</th><th>金额（约）</th><th>申请难度</th><th>说明</th></tr></thead><tbody><tr><td><strong>CSC国家建设高水平大学公派研究生项目</strong></td><td>国家留学基金委</td><td>含学费+生活费</td><td>高</td><td>面向出国读博，不适用于回国读博</td></tr><tr><td><strong>中国政府奖学金（CSC）</strong></td><td>国家留学基金委</td><td>学费+住宿+生活费</td><td>高</td><td>主要面向来华留学生</td></tr><tr><td><strong>学校学业奖学金</strong></td><td>各高校</td><td>覆盖学费+生活费补贴</td><td>中</td><td>覆盖面广，各校标准不同</td></tr><tr><td><strong>校长奖学金/优秀博士论文资助</strong></td><td>各高校</td><td>额外奖励</td><td>高</td><td>竞争性申请</td></tr><tr><td><strong>导师助研津贴</strong></td><td>导师科研经费</td><td>每月2000-5000元</td><td>低</td><td>大部分导师都会提供</td></tr><tr><td><strong>国家助学金</strong></td><td>国家财政</td><td>每年约15000元</td><td>极低</td><td>全日制博士生基本都有</td></tr></tbody></table><h2 id="典型博士收入构成" tabindex="-1">典型博士收入构成 <a class="header-anchor" href="#典型博士收入构成" aria-label="Permalink to &quot;典型博士收入构成&quot;">​</a></h2><p>以清华/北大/上交等校为例，博士生月收入大致如下：</p><table tabindex="0"><thead><tr><th>来源</th><th>金额（元/月）</th><th>说明</th></tr></thead><tbody><tr><td>国家助学金</td><td>1250</td><td>所有全日制博士生均有</td></tr><tr><td>学校奖学金</td><td>800-2500</td><td>视成绩和评定等级</td></tr><tr><td>导师助研津贴</td><td>1500-5000</td><td>各课题组差异大，科研经费充足的企业导师通常给得更多</td></tr><tr><td><strong>合计</strong></td><td><strong>3500 — 8750</strong></td><td>视学校和导师差异</td></tr></tbody></table><blockquote><p>一线城市（北京、上海）生活成本较高，但学校通常提供廉价宿舍（约1000-2000元/年）和食堂补贴，实际生活负担可控。</p></blockquote><h2 id="各校奖学金特点" tabindex="-1">各校奖学金特点 <a class="header-anchor" href="#各校奖学金特点" aria-label="Permalink to &quot;各校奖学金特点&quot;">​</a></h2><h3 id="清华大学" tabindex="-1">清华大学 <a class="header-anchor" href="#清华大学" aria-label="Permalink to &quot;清华大学&quot;">​</a></h3><ul><li><strong>未来学者奖学金</strong>：面向优秀博士生，额外奖励</li><li><strong>清华学堂人才培养计划</strong>：部分学科有专项</li><li>导师助研津贴通常较为充足</li></ul><h3 id="北京大学" tabindex="-1">北京大学 <a class="header-anchor" href="#北京大学" aria-label="Permalink to &quot;北京大学&quot;">​</a></h3><ul><li><strong>校长奖学金</strong>：每年评选，金额7万元+</li><li><strong>北大-清华生命科学联合中心</strong>：提供额外博士生奖学金</li></ul><h3 id="上海交通大学" tabindex="-1">上海交通大学 <a class="header-anchor" href="#上海交通大学" aria-label="Permalink to &quot;上海交通大学&quot;">​</a></h3><ul><li><strong>优秀博士学位论文资助</strong>：资助优秀博士论文研究</li><li><strong>致远荣誉计划</strong>：面向优秀博士生</li></ul><h3 id="浙江大学" tabindex="-1">浙江大学 <a class="header-anchor" href="#浙江大学" aria-label="Permalink to &quot;浙江大学&quot;">​</a></h3><ul><li><strong>争创优秀博士学位论文资助</strong>：每年评选</li><li>国际合作培养项目资助</li></ul><h3 id="中国科学院" tabindex="-1">中国科学院 <a class="header-anchor" href="#中国科学院" aria-label="Permalink to &quot;中国科学院&quot;">​</a></h3><ul><li>各研究所待遇差异较大</li><li>自动化所、神经所等一线所博士生月收入约5000-8000元</li><li>部分所提供所内宿舍</li></ul><h2 id="海外硕士回国申博的资助注意事项" tabindex="-1">海外硕士回国申博的资助注意事项 <a class="header-anchor" href="#海外硕士回国申博的资助注意事项" aria-label="Permalink to &quot;海外硕士回国申博的资助注意事项&quot;">​</a></h2><ul><li>海外硕士与国内硕士在奖学金方面通常享有同等待遇</li><li>部分学校对留学生（指国籍非中国）有专门奖学金，但你不适用</li><li>CSC奖学金中的「自费生转公费」政策：部分学校允许第一年自费、第二年根据表现转为公费</li></ul><h2 id="奖学金申请时间线" tabindex="-1">奖学金申请时间线 <a class="header-anchor" href="#奖学金申请时间线" aria-label="Permalink to &quot;奖学金申请时间线&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时间</th><th>事项</th></tr></thead><tbody><tr><td>博士录取后</td><td>大部分奖学金自动评定，无需单独申请</td></tr><tr><td>入学后</td><td>可申请各类专项奖学金、竞赛奖金</td></tr><tr><td>博士第3-4年</td><td>可申请优秀博士论文资助</td></tr></tbody></table><h2 id="其他资助渠道" tabindex="-1">其他资助渠道 <a class="header-anchor" href="#其他资助渠道" aria-label="Permalink to &quot;其他资助渠道&quot;">​</a></h2><ul><li><strong>国家自然科学基金青年学生基础研究项目</strong>：面向博士生的科研资助</li><li><strong>校企合作项目津贴</strong>：参与企业横向课题的额外收入</li><li><strong>国际学术会议旅费资助</strong>：学校通常资助博士生参加国际会议</li><li><strong>CSC联合培养</strong>：博士期间可申请CSC资助出国联合培养1-2年</li></ul><blockquote><p>建议在联系导师时了解课题组的助研津贴情况，这是博士生收入的主要构成部分。可以在适当的时候（如导师表示有兴趣接收你之后）委婉询问。</p></blockquote>',25)])])}const g=d(e,[["render",o]]);export{b as __pageData,g as default};
